import { MakeLogicType, afterMount, kea, path } from 'kea'
import { loaders } from 'kea-loaders'

import api from 'lib/api'

import { LinkType } from '~/types'


// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface linksLogicValues {
    links: LinkType[];
    linksLoading: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface linksLogicActions {
    loadLinks: () => any;
    loadLinksFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadLinksSuccess: (links: LinkType[], payload?: any) => {
        links: LinkType[];
        payload?: any;
    };
}

export type linksLogicType = MakeLogicType<linksLogicValues, linksLogicActions>;

export const linksLogic = kea<linksLogicType>([
    path(() => ['scenes', 'links', 'linksLogic']),
    loaders(() => ({
        links: [
            [] as LinkType[],
            {
                loadLinks: async () => {
                    const response = await api.links.list()
                    return response.results
                },
            },
        ],
    })),

    afterMount(({ actions }) => {
        actions.loadLinks()
    }),
])
